@app.route('/api/documents/<doc_id>', methods=['PUT'])
def update_document(doc_id):
    """Update a document with version tracking."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    try:
        existing_doc = documents_collection.find_one({'_id': ObjectId(doc_id)})
        if not existing_doc:
            return jsonify({'error': 'Document not found'}), 404

        allowed_fields = ['title', 'content', 'category', 'tags', 'status', 'metadata']
        update_data = {k: v for k, v in data.items() if k in allowed_fields}
        update_data['updated_at'] = datetime.utcnow()

        # Version tracking
        version_entry = {
            'version': existing_doc['version'],
            'title': existing_doc['title'],
            'content': existing_doc['content'],
            'updated_at': existing_doc['updated_at']
        }

        # Handle publish status change
        if update_data.get('status') == 'published' and existing_doc['status'] != 'published':
            update_data['published_at'] = datetime.utcnow()

        result = documents_collection.update_one(
            {'_id': ObjectId(doc_id)},
            {
                '$set': update_data,
                '$inc': {'version': 1},
                '$push': {'version_history': version_entry}
            }
        )

        updated_doc = documents_collection.find_one({'_id': ObjectId(doc_id)})
        return jsonify({'message': 'Document updated successfully', 'document': serialize_doc(updated_doc)}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/api/documents/<doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    """Delete a document."""
    try:
        document = documents_collection.find_one({'_id': ObjectId(doc_id)})
        if not document:
            return jsonify({'error': 'Document not found'}), 404

        documents_collection.delete_one({'_id': ObjectId(doc_id)})
        # Update user's document count
        users_collection.update_one(
            {'_id': document['author_id']},
            {'$inc': {'document_count': -1}}
        )
        return jsonify({'message': 'Document deleted successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400


