@app.route('/api/documents/search', methods=['GET'])
def search_documents():
    """Full-text search across documents."""
    query_text = request.args.get('q', '')
    if not query_text:
        return jsonify({'error': 'Search query is required'}), 400

    page = int(request.args.get('page', 1))
    per_page = int(request.args.get('per_page', 10))
    skip = (page - 1) * per_page

    search_query = {
        '$text': {'$search': query_text},
        'status': 'published'
    }

    total = documents_collection.count_documents(search_query)
    documents = list(
        documents_collection.find(
            search_query,
            {'score': {'$meta': 'textScore'}}
        )
        .sort([('score', {'$meta': 'textScore'})])
        .skip(skip)
        .limit(per_page)
    )

    return jsonify({
        'documents': [serialize_doc(d) for d in documents],
        'total': total,
        'page': page,
        'per_page': per_page,
        'query': query_text
    }), 200


@app.route('/api/documents/by-tags', methods=['GET'])
def get_documents_by_tags():
    """Get documents matching multiple tags."""
    tags = request.args.getlist('tags')
    match_all = request.args.get('match_all', 'false').lower() == 'true'

    if not tags:
        return jsonify({'error': 'At least one tag is required'}), 400

    if match_all:
        query = {'tags': {'$all': tags}, 'status': 'published'}
    else:
        query = {'tags': {'$in': tags}, 'status': 'published'}

    documents = list(
        documents_collection.find(query).sort('created_at', DESCENDING).limit(50)
    )

    return jsonify({
        'documents': [serialize_doc(d) for d in documents],
        'total': len(documents),
        'tags': tags,
        'match_all': match_all
    }), 200


@app.route('/api/documents/date-range', methods=['GET'])
def get_documents_by_date_range():
    """Get documents within a date range."""
    start_date = request.args.get('start_date')
    end_date = request.args.get('end_date')

    if not start_date or not end_date:
        return jsonify({'error': 'Both start_date and end_date are required (YYYY-MM-DD)'}), 400

    try:
        start = datetime.strptime(start_date, '%Y-%m-%d')
        end = datetime.strptime(end_date, '%Y-%m-%d')
    except ValueError:
        return jsonify({'error': 'Invalid date format. Use YYYY-MM-DD'}), 400

    query = {
        'created_at': {'$gte': start, '$lte': end},
        'status': 'published'
    }

    documents = list(
        documents_collection.find(query).sort('created_at', DESCENDING)
    )

    return jsonify({
        'documents': [serialize_doc(d) for d in documents],
        'total': len(documents),
        'start_date': start_date,
        'end_date': end_date
    }), 200


