@app.route('/api/analytics/content-stats', methods=['GET'])
def get_content_stats():
    """Get overall content statistics using aggregation."""
    pipeline = [
        {
            '$group': {
                '_id': None,
                'total_documents': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'avg_views': {'$avg': '$views'},
                'avg_likes': {'$avg': '$likes'},
                'max_views': {'$max': '$views'},
                'max_likes': {'$max': '$likes'}
            }
        }
    ]

    result = list(documents_collection.aggregate(pipeline))
    stats = result[0] if result else {
        'total_documents': 0,
        'total_views': 0,
        'total_likes': 0,
        'avg_views': 0,
        'avg_likes': 0,
        'max_views': 0,
        'max_likes': 0
    }
    if '_id' in stats:
        del stats['_id']

    return jsonify({'stats': parse_json(stats)}), 200


