@app.route('/api/analytics/top-authors', methods=['GET'])
def get_top_authors():
    """Get top authors by document count and engagement."""
    limit = int(request.args.get('limit', 10))

    pipeline = [
        {
            '$group': {
                '_id': '$author_id',
                'document_count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'published_count': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                }
            }
        },
        {'$sort': {'total_views': -1}},
        {'$limit': limit},
        {
            '$lookup': {
                'from': 'users',
                'localField': '_id',
                'foreignField': '_id',
                'as': 'author_info'
            }
        },
        {'$unwind': {'path': '$author_info', 'preserveNullAndEmptyArrays': True}},
        {
            '$project': {
                'author_id': '$_id',
                'username': '$author_info.username',
                'full_name': '$author_info.full_name',
                'document_count': 1,
                'published_count': 1,
                'total_views': 1,
                'total_likes': 1,
                '_id': 0
            }
        }
    ]

    result = list(documents_collection.aggregate(pipeline))
    return jsonify({'top_authors': parse_json(result)}), 200


