@app.route('/api/analytics/monthly-activity', methods=['GET'])
def get_monthly_activity():
    """Get document creation activity by month."""
    year = int(request.args.get('year', datetime.utcnow().year))

    pipeline = [
        {
            '$match': {
                'created_at': {
                    '$gte': datetime(year, 1, 1),
                    '$lt': datetime(year + 1, 1, 1)
                }
            }
        },
        {
            '$group': {
                '_id': {
                    'year': {'$year': '$created_at'},
                    'month': {'$month': '$created_at'}
                },
                'documents_created': {'$sum': 1},
                'documents_published': {
                    '$sum': {'$cond': [{'$eq': ['$status', 'published']}, 1, 0]}
                },
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'}
            }
        },
        {'$sort': {'_id.month': 1}},
        {
            '$project': {
                'year': '$_id.year',
                'month': '$_id.month',
                'documents_created': 1,
                'documents_published': 1,
                'total_views': 1,
                'total_likes': 1,
                '_id': 0
            }
        }
    ]

    result = list(documents_collection.aggregate(pipeline))
    return jsonify({'monthly_activity': parse_json(result), 'year': year}), 200


